s = {1, 2, 3, 3}
print(s)               # {1, 2, 3}

# Set operations
a = {1, 2, 3}
b = {3, 4, 5}
print(a | b)           # {1, 2, 3, 4, 5} (Union)
print(a & b)           # {3}             (Intersection)
print(a - b)           # {1, 2}          (Difference)

user = {"name": "Alice", "role": "admin"}
print(user["name"])    # "Alice"
print(user.get("age", 25)) # 25 (safe access with default fallback)

# Insertion & Merging (Python 3.9+)
merged = user | {"active": True}
print(merged)          # {'name': 'Alice', 'role': 'admin', 'active': True}
